-  currentUtterance = utterance;
-  speechSynthesis.speak(utterance);
-  return true;
-}
-
-export function stopTts(): void {
-  if (currentUtterance) {
-    currentUtterance = null;
-  }
-  if (isTtsSupported()) {
-    speechSynthesis.cancel();
-  }
-}
-
-export function isTtsSpeaking(): boolean {
-  return isTtsSupported() && speechSynthesis.speaking;
-}
-
-/** Strip common markdown syntax for cleaner speech output. */
-function stripMarkdown(text: string): string {
-  return (
-    text
-      // code blocks
-      .replace(/```[\s\S]*?```/g, "")
-      // inline code
-      .replace(/`[^`]+`/g, "")
-      // images
-      .replace(/!\[.*?\]\(.*?\)/g, "")
-      // links → keep text
-      .replace(/\[([^\]]+)\]\(.*?\)/g, "$1")
-      // headings
-      .replace(/^#{1,6}\s+/gm, "")
-      // bold/italic
-      .replace(/\*{1,3}(.*?)\*{1,3}/g, "$1")
-      .replace(/_{1,3}(.*?)_{1,3}/g, "$1")
-      // blockquotes
-      .replace(/^>\s?/gm, "")
-      // horizontal rules
-      .replace(/^[-*_]{3,}\s*$/gm, "")
-      // list markers
-      .replace(/^\s*[-*+]\s+/gm, "")
-      .replace(/^\s*\d+\.\s+/gm, "")
-      // HTML tags
-      .replace(/<[^>]+>/g, "")
-      // collapse whitespace
-      .replace(/\n{3,}/g, "\n\n")
-      .trim()
-  );
-}
